async (page) => {
  // Kill the wounded Batterfly (19 HP) then hit the next one
  for (let i = 0; i < 5; i++) {
    const bat = await page.evaluate(() => {
      const gs = window.__latestGameState;
      return gs?.nearby_entities?.find(e => e.name === 'Batterfly' && e.on_screen && e.hp > 0);
    });
    if (!bat) { 
      await page.waitForTimeout(2000); 
      continue; 
    }
    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, {x: bat.click_x, y: bat.click_y});
    await page.waitForTimeout(6000);

    const hp = await page.evaluate(() => window.__latestGameState?.player_stats?.hp);
    if (hp < 60) break; // Stop if HP too low
  }

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {
      hp: gs?.player_stats?.hp, max_hp: gs?.player_stats?.max_hp,
      level: gs?.player_stats?.level,
      pos: gs?.player_position,
      nearby: gs?.nearby_entities?.slice(0,6)?.map(e => ({name: e.name, hp: e.hp, dist: e.distance, on_screen: e.on_screen}))
    };
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

async (page) => {
  // Extended grind loop - keep killing Batterflies
  for (let i = 0; i < 8; i++) {
    const target = await page.evaluate(() => {
      const gs = window.__latestGameState;
      // Prefer wounded targets
      const mobs = gs?.nearby_entities?.filter(e => e.type === 3 && e.on_screen && e.hp > 0) || [];
      mobs.sort((a,b) => a.hp - b.hp); // hit lowest HP first
      return mobs[0] || null;
    });

    if (!target) { await page.waitForTimeout(2000); continue; }

    await page.evaluate(({x, y}) => {
      document.getElementById('canvas').dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, {x: target.click_x, y: target.click_y});
    await page.waitForTimeout(6000);

    const hp = await page.evaluate(() => window.__latestGameState?.player_stats?.hp);
    const maxhp = await page.evaluate(() => window.__latestGameState?.player_stats?.max_hp);
    if (hp / maxhp < 0.35) break; // Stop if below 35% HP
  }

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    return {hp: gs?.player_stats?.hp, max_hp: gs?.player_stats?.max_hp, level: gs?.player_stats?.level, pos: gs?.player_position};
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

