  for (const t of targets) {
    const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), t);
    await page.waitForTimeout(4000);
    pos = await page.evaluate(() => window.__latestGameState?.player_position);
  }

  const nearby = await page.evaluate(() => {
