        const name = entity.name || entity.id;
        if (name && (name.toLowerCase().includes('grandma') || name.toLowerCase().includes('granny') || name.toLowerCase().includes('old lady') || name.toLowerCase().includes('elder'))) {
          found.push({ id, name, x: entity.gridX, y: entity.gridY, type: entity.type });
        }
      }
    }

    // Also check the Scavenger quest data
    const scavQuest = window.game?.player?.quests?.['scavenger'];

    return JSON.stringify({ 
      found, 
      questData: scavQuest ? { stage: scavQuest.stage, subStage: scavQuest.subStage, description: scavQuest.description } : null
    });
  });
  return result;
}

