  await page.evaluate(({x,y}) => window.__clickTile(x, y), {x: 288, y: 134});
  await page.waitForTimeout(5000);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const soldier = s.nearby_entities.find(e => e.name?.includes('Dying') || e.name?.includes('Soldier') || e.name?.includes('Adventurer'));
    return {pos: s.player_position, soldier: soldier ? {name:soldier.name, id:soldier.id, dist:soldier.distance, quest_npc:soldier.quest_npc} : null};
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify(state);
}

async (page) => {
  // Keep navigating east in steps
  for (const [x, y] of [[270, 134], [285, 134], [288, 133]]) {
