}

async (page) => {
  // Navigate east and south toward (333,281)
  // First check current position and navigate to (310,200) area
  const steps = [[310, 134], [333, 134], [333, 200], [333, 250], [333, 281]];

  for (const [x, y] of steps) {
    await page.evaluate(({x,y}) => window.__clickTile(x, y), {x, y});
    await page.waitForTimeout(3000);
    const pos = await page.evaluate(() => window.__latestGameState?.player_position);
    console.log(`Target (${x},${y}) → ${JSON.stringify(pos)}`);
    // Check if we got stuck
    if (Math.abs(pos.x - x) > 20 || Math.abs(pos.y - y) > 20) {
      console.log('Got stuck, breaking');
    }
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const npcs = s.nearby_entities.filter(e => e.type === 1).map(e => ({name:e.name,x:e.x,y:e.y,dist:e.distance}));
    return JSON.stringify({pos: s.player_position, hp: s.player_stats.hp, npcs: npcs.slice(0,5)});
  });
  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return state;
}

