async (page) => {
  // Click on Forester entity to walk adjacent
  const foresterLabel = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    if (!m || m.error) return null;
    const match = m.legendText.match(/E(\d+) \[[\?\!N]\] Forester/);
    return match ? 'E' + match[1] : null;
  });

  if (foresterLabel) {
    const r = await page.evaluate((lbl) => JSON.stringify(window.__clickEntity(lbl)), foresterLabel);
    await page.waitForTimeout(4000);
  } else {
    // Navigate directly
    await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 216, y: 114});
    await page.waitForTimeout(5000);
