    const gs = window.__latestGameState;
    return gs.nearby_entities.filter(e => e.name === 'Forester').map(e => ({name: e.name, id: e.id, dist: e.distance}));
  });

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
  return JSON.stringify({pos, forester, foresterLabel});
}

