async (page) => {
  // Walk to Blueberry Bush at (203,120)
  await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 202, y: 120});
  await page.waitForTimeout(3000);

  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  const legend = await page.evaluate(() => window.__latestAsciiMap.legendText);

  // Find blueberry bush in legend and click it
  const match = legend.match(/E(\d+) \[~\] Blueberry Bush at \((\d+),(\d+)\) dist=(\d+)/);
  if (match && parseInt(match[4]) <= 2) {
    const label = 'E' + match[1];
    const r = await page.evaluate((lbl) => JSON.stringify(window.__clickEntity(lbl)), label);
    await page.waitForTimeout(3000);

    const inv = await page.evaluate(() => window.__latestGameState.inventory.map(i => i.name));
    const lj = await page.evaluate(() => ({
      foraging: window.game.player.skills[15].level,
      foragingExp: window.game.player.skills[15].experience
    }));

    await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });
    return JSON.stringify({clicked: label, pos, inv, skills: lj});
  }

  return JSON.stringify({pos, legend: legend.slice(0, 200)});
}

async (page) => {
  // Click Village Girl to walk adjacent
  await page.evaluate((label) => window.__clickEntity(label), 'E0');
  await page.waitForTimeout(3000);

  // Talk to Village Girl
  for (let i = 0; i < 4; i++) {
    await page.evaluate((id) => window.__talkToNPC(id), '1-75571336');
    await page.waitForTimeout(1200);
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });

  const info = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const quest = gs?.quests?.find(q => q.key === 'scavenger');
    const btn = document.getElementById('quest-button');
    const btnVisible = btn ? window.getComputedStyle(btn).display : 'none';
    const questTitle = document.getElementById('quest-title')?.textContent;
    return JSON.stringify({
      pos: gs?.player_position,
      scavengerQuest: quest,
      questBtnVisible: btnVisible,
      questTitle
    });
  });
  return info;
}

