async (page) => {
  // Navigate to Forester
  await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 213, y: 115});
  await page.waitForTimeout(4000);

  // Walk to Forester
  const legend = await page.evaluate(() => window.__latestAsciiMap?.legendText || '');
  const match = legend.match(/E(\d+) \[.\] Forester/);
  if (match) {
    await page.evaluate((l) => window.__clickEntity(l), 'E' + match[1]);
    await page.waitForTimeout(3000);
  }

  // Talk to Forester multiple times
  for (let i = 0; i < 5; i++) {
    await page.evaluate((id) => window.__talkToNPC(id), '1-45313128');
    await page.waitForTimeout(1200);
  }

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });

  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const quest = gs?.quests?.find(q => q.key === 'foresting');
    const logs = gs?.inventory?.filter(i => i.key === 'logs').reduce((s, i) => s + i.count, 0) || 0;
    const btn = document.getElementById('quest-button');
    const btnText = btn ? btn.textContent : 'none';
    return JSON.stringify({pos: gs?.player_position, quest, logs, btnText});
  });
  return state;
}

