async (page) => {
  await page.evaluate(() => {
    window.game.menu.warp.show();
    setTimeout(() => document.getElementById('warp0').click(), 500);
  });
  await page.waitForTimeout(4000);

  await page.screenshot({ path: '/tmp/kaetram_agent_0/state/screenshot.png', type: 'png' });

  // Check nearby entities for any quest NPCs
  const result = await page.evaluate(() => {
    const gs = window.__latestGameState;
    const entities = gs?.nearby_entities?.slice(0, 20).filter(e => e.type === 1).map(e => 
      `${e.name}(type=${e.type}) at (${e.x},${e.y}) dist=${e.distance} quest=${e.quest_npc} achieve=${e.has_achievement} id=${e.id}`
    );
    return JSON.stringify({ pos: gs?.player_position, npcs: entities });
  });
  return result;
}
